def store_info_in_header(
    info_type: str, info_content: str, header: Dict[str, str]
) -> Dict[str, str]:
    mapping = {
        'lang': 'Accept-Language',
        'encoding': 'Accept-Encoding',
        'cache': 'Cache-Control'
    }
    if info_type not in mapping:
        return header
    try:
        # Sanitize input to prevent HTTP Response Splitting / Header Injection
        sanitized_content = info_content.replace('\r', '').replace('\n', '')
        header[mapping[info_type]] = sanitized_content
        return header
    except Exception:
        return header

